 1→import { createSignal, type JSX, Show } from "solid-js";
 2→import { Check, Copy } from "@/components/icons";
 3→import { Button } from "./Button";
 4→import styles from "./CopyButton.module.css";
 5→
 6→type Props = {
 7→    text: string;
 8→    label?: string;
 9→    class?: string;
10→    disabled?: boolean;
11→};
12→
13→export function CopyButton(props: Props): JSX.Element {
14→    const [copied, setCopied] = createSignal(false, { name: "copied" });
15→
16→    const handleCopy = async () => {
17→        try {
18→            await navigator.clipboard.writeText(props.text);
19→            setCopied(true);
20→            setTimeout(() => setCopied(false), 2000);
21→        } catch {
22→            const textArea = document.createElement("textarea");
23→            textArea.value = props.text;
24→            textArea.style.position = "fixed";
25→            textArea.style.left = "-999999px";
26→            document.body.appendChild(textArea);
27→            textArea.select();
28→            try {
29→                document.execCommand("copy");
30→                setCopied(true);
31→                setTimeout(() => setCopied(false), 2000);
32→            } catch (exception) {
33→                console.error("Failed to copy:", exception);
34→            }
35→            document.body.removeChild(textArea);
36→        }
37→    };
38→
39→    return (
40→        <Button
41→            variant="ghost"
42→            size={props.label ? "small" : "icon"}
43→            class={`${styles.button} ${props.class ?? ""}`}
44→            tooltip={copied() ? "Copied!" : "Copy to clipboard"}
45→            onClick={handleCopy}
46→            disabled={props.disabled}
47→        >
48→            <Show when={copied()}>
49→                <Check size={14} class={styles.check} />
50→            </Show>
51→            <Show when={!copied()}>
52→                <Copy size={14} />
53→            </Show>
54→            <Show when={props.label}>
55→                <span class={styles.label}>{copied() ? "Copied!" : props.label}</span>
56→            </Show>
57→        </Button>
58→    );
59→}
