 10→export function JsonSection(props: {
 11→    title: string;
 12→    data: unknown;
 13→    defaultOpen?: boolean;
 14→    /** When false, the section is always open with no chevron toggle. Defaults to true. */
 15→    expandable?: boolean;
 16→    /** When provided, enables a diff toggle that shows side-by-side comparison against this data */
 17→    diffOriginal?: unknown;
 18→    /** When provided, shows a help icon next to the title with this content in a hover card */
 19→    help?: JSX.Element;
