 92→                            color: "var(--foreground)",
 93→                        }}
 94→                    >
 95→                        {props.title}
 96→                        <Show when={props.help}>
 97→                            <HelpTrigger>{props.help}</HelpTrigger>
 98→                        </Show>
 99→                    </span>
100→                </Show>
101→                <div style={{ display: "flex", "align-items": "center", gap: "0.25rem", "flex-shrink": "0" }}>
102→                    <Button
103→                        variant="ghost"
104→                        size="icon"
105→                        tooltip="Expand all"
106→                        onClick={async () => {
107→                            if (!editorView) return;
108→                            const { unfoldAll } = await import("@codemirror/language");
109→                            unfoldAll(editorView);
110→                        }}
111→                    >
112→                        <UnfoldVertical size={14} />
113→                    </Button>
114→                    <Button
115→                        variant="ghost"
116→                        size="icon"
117→                        tooltip="Collapse all"
118→                        onClick={async () => {
119→                            if (!editorView) return;
120→                            const { foldAll } = await import("@codemirror/language");
121→                            foldAll(editorView);
122→                        }}
123→                    >
124→                        <FoldVertical size={14} />
125→                    </Button>
126→                    <Show when={props.diffOriginal !== undefined}>
127→                        <Button
128→                            variant="ghost"
129→                            size="icon"
130→                            tooltip={showDiff() ? "Hide diff" : "Show diff against original"}
131→                            onClick={() => setShowDiff(!showDiff())}
132→                            style={{
133→                                color: showDiff() ? "var(--secondary)" : undefined,
134→                            }}
135→                        >
136→                            <GitCompareArrows size={14} />
137→                        </Button>
138→                    </Show>
139→                    <CopyButton text={jsonString()} />
140→                </div>
141→            </div>
142→            <Show when={contentVisible()}>
143→                <Show
144→                    when={showDiff() && props.diffOriginal !== undefined}
145→                    fallback={<JsonHighlight code={jsonString()} onEditorView={(view) => (editorView = view)} />}
146→                >
147→                    <JsonDiffViewer original={props.diffOriginal} modified={props.data} />
148→                </Show>
149→            </Show>
150→        </div>
151→    );
