 1→import { EditorState } from "@codemirror/state";
 2→import { EditorView } from "@codemirror/view";
 3→import { type JSX, onCleanup } from "solid-js";
 4→import { readonlyJsonExtensions } from "./codemirror-extensions";
 5→import styles from "./JsonHighlight.module.css";
 6→
 7→export function JsonHighlight(props: {
 8→    code: string;
 9→    lineNumbers?: boolean;
10→    onEditorView?: (view: EditorView) => void;
11→}): JSX.Element {
12→    let editorView: EditorView | undefined;
13→
14→    const createEditor = (el: HTMLDivElement) => {
15→        editorView = new EditorView({
16→            state: EditorState.create({
17→                doc: props.code,
18→                extensions: readonlyJsonExtensions({ lineNumbers: props.lineNumbers }),
19→            }),
20→            parent: el,
21→        });
22→        props.onEditorView?.(editorView);
23→    };
24→
25→    onCleanup(() => {
26→        editorView?.destroy();
27→    });
28→
29→    return <div class={styles.jsonHighlight} ref={createEditor} />;
30→}
