.container {
    font-family: var(--monospace-font);
    font-size: var(--small-font-size);
    background: var(--muted-background);
    border-radius: var(--radius);
    max-height: 400px;
    overflow: auto;
    padding: 0.75rem;
    line-height: 1.5;
}

.node {
    position: relative;
}

.node-highlighted {
    background: color-mix(in srgb, var(--foreground) 6%, transparent);
    border-radius: var(--radius);
}

.toggle {
    display: inline;
    border: none;
    background: transparent;
    color: inherit;
    font: inherit;
    cursor: pointer;
    padding: 0;
    margin: 0;
}

.toggle:hover {
    opacity: 0.7;
}

.chevron {
    display: inline-block;
    width: 14px;
    height: 14px;
    vertical-align: middle;
    transition: transform 0.15s ease;
    margin-right: 2px;
    color: var(--muted-foreground);
}

.chevron-expanded {
    transform: rotate(90deg);
}

.children {
    padding-left: 1.25rem;
}

.property-name {
    color: oklch(0.50 0.18 18);
}

.string {
    color: oklch(0.55 0.15 145);
}

.number {
    color: oklch(0.55 0.18 250);
}

.boolean {
    color: oklch(0.55 0.2 310);
}

.null {
    color: oklch(0.55 0.1 30);
}

.punctuation {
    color: oklch(0.55 0 0);
}

.preview {
    color: var(--muted-foreground);
    font-style: italic;
}

.copy-wrapper {
    position: absolute;
    top: 0;
    right: 0;
    z-index: 1;
}

import { createEffect, createSignal, For, type JSX, on, Show } from "solid-js";
import { ChevronRight } from "@/components/icons";
import { CopyButton } from "@/components/primitives/CopyButton";
import styles from "./JsonTreeViewer.module.css";

export function JsonTreeViewer(props: {
    data: unknown;
    defaultExpandDepth?: number;
    expandGeneration?: number;
    collapseGeneration?: number;
}): JSX.Element {
    const defaultDepth = () => props.defaultExpandDepth ?? 1;
    const [expandState, setExpandState] = createSignal<Map<string, boolean>>(new Map(), {
        name: "expandState",
    });
    const [hoveredPath, setHoveredPath] = createSignal<string | undefined>(undefined, {
        name: "hoveredPath",
    });

    createEffect(
        on(
            () => props.expandGeneration,
            (generation, previousGeneration) => {
                if (generation === undefined || generation === previousGeneration) return;
                const paths = collectPaths(props.data, "$");
                const next = new Map<string, boolean>();
                for (const path of paths) {
                    next.set(path, true);
                }
                setExpandState(next);
            },
        ),
    );

    createEffect(
        on(
            () => props.collapseGeneration,
            (generation, previousGeneration) => {
                if (generation === undefined || generation === previousGeneration) return;
                const paths = collectPaths(props.data, "$");
                const next = new Map<string, boolean>();
                for (const path of paths) {
                    next.set(path, false);
                }
                setExpandState(next);
            },
        ),
    );

    const isExpanded = (path: string, depth: number): boolean => {
        const explicit = expandState().get(path);
        if (explicit !== undefined) return explicit;
        return depth < defaultDepth();
    };

    const toggleExpanded = (path: string, depth: number) => {
        const current = isExpanded(path, depth);
        setExpandState((previous) => {
            const next = new Map(previous);
            next.set(path, !current);
            return next;
        });
    };

    return (
        <div class={styles.container} data-label="JsonTreeViewer">
            <JsonNode
                value={props.data}
                path="$"
                depth={0}
                isExpanded={isExpanded}
                toggleExpanded={toggleExpanded}
                hoveredPath={hoveredPath}
                setHoveredPath={setHoveredPath}
            />
        </div>
    );
}

function JsonNode(props: {
    value: unknown;
    path: string;
    depth: number;
    keyName?: string;
    isLast?: boolean;
    isExpanded: (path: string, depth: number) => boolean;
    toggleExpanded: (path: string, depth: number) => void;
    hoveredPath: () => string | undefined;
    setHoveredPath: (path: string | undefined) => void;
}): JSX.Element {
    const isLast = () => props.isLast !== false;
    const comma = () => (isLast() ? "" : ",");

    const isCompound = () => {
        const value = props.value;
        return value !== null && typeof value === "object";
    };

    const isHighlighted = () => isCompound() && props.hoveredPath() === props.path;

    const onMouseEnter = (event: MouseEvent) => {
        event.stopPropagation();
        props.setHoveredPath(props.path);
    };

    const onMouseLeave = (event: MouseEvent) => {
        event.stopPropagation();
        if (props.hoveredPath() === props.path) {
            props.setHoveredPath(undefined);
        }
    };

    const keyPrefix = (): JSX.Element => (
        <Show when={props.keyName !== undefined}>
            <span class={styles["property-name"]}>"{props.keyName}"</span>
            <span class={styles.punctuation}>: </span>
        </Show>
    );

    // Primitive values
    const renderPrimitive = (): JSX.Element => {
        const value = props.value;
        if (value === null) {
            return (
                <div>
                    {keyPrefix()}
                    <span class={styles.null}>null</span>
                    {comma()}
                </div>
            );
        }
        if (typeof value === "string") {
            return (
                <div>
                    {keyPrefix()}
                    <span class={styles.string}>"{escapeString(value)}"</span>
                    {comma()}
                </div>
            );
        }
        if (typeof value === "number") {
            return (
                <div>
                    {keyPrefix()}
                    <span class={styles.number}>{String(value)}</span>
                    {comma()}
                </div>
            );
        }
        if (typeof value === "boolean") {
            return (
                <div>
                    {keyPrefix()}
                    <span class={styles.boolean}>{String(value)}</span>
                    {comma()}
                </div>
            );
        }
        return (
            <div>
                {keyPrefix()}
                <span>{String(value)}</span>
                {comma()}
            </div>
        );
    };

    // Compound values (object/array)
    const renderCompound = (): JSX.Element => {
        const value = props.value as Record<string, unknown> | unknown[];
        const isArray = Array.isArray(value);
        const openBracket = isArray ? "[" : "{";
        const closeBracket = isArray ? "]" : "}";
        const entries = isArray
            ? value.map((item, index) => ({ key: String(index), value: item }))
            : Object.entries(value);
        const count = entries.length;
        const expanded = () => props.isExpanded(props.path, props.depth);
        const preview = () => (isArray ? `${count} items` : `${count} keys`);

        return (
            <div
                class={`${styles.node} ${isHighlighted() ? styles["node-highlighted"] : ""}`}
                onMouseEnter={onMouseEnter}
                onMouseLeave={onMouseLeave}
            >
                <Show when={isHighlighted()}>
                    <div class={styles["copy-wrapper"]}>
                        <CopyButton text={JSON.stringify(props.value, null, 2)} />
                    </div>
                </Show>
                <div>
                    <button
                        type="button"
                        class={styles.toggle}
                        onClick={() => props.toggleExpanded(props.path, props.depth)}
                    >
                        <ChevronRight
                            size={14}
                            class={`${styles.chevron} ${expanded() ? styles["chevron-expanded"] : ""}`}
                        />
                    </button>
                    {keyPrefix()}
                    <span class={styles.punctuation}>{openBracket}</span>
                    <Show when={!expanded()}>
                        <span
                            class={styles.preview}
                            onClick={() => props.toggleExpanded(props.path, props.depth)}
                            style={{ cursor: "pointer" }}
                        >
                            {" "}
                            ... {preview()}{" "}
                        </span>
                        <span class={styles.punctuation}>{closeBracket}</span>
                        {comma()}
                    </Show>
                </div>
                <Show when={expanded()}>
                    <div class={styles.children}>
                        <For each={entries}>
                            {(entry, index) => (
                                <JsonNode
                                    value={entry.value}
                                    path={`${props.path}.${entry.key}`}
                                    depth={props.depth + 1}
                                    keyName={isArray ? undefined : entry.key}
                                    isLast={index() === entries.length - 1}
                                    isExpanded={props.isExpanded}
                                    toggleExpanded={props.toggleExpanded}
                                    hoveredPath={props.hoveredPath}
                                    setHoveredPath={props.setHoveredPath}
                                />
                            )}
                        </For>
                    </div>
                    <div>
                        <span class={styles.punctuation}>{closeBracket}</span>
                        {comma()}
                    </div>
                </Show>
            </div>
        );
    };

    return (
        <>
            <Show when={isCompound()}>{renderCompound()}</Show>
            <Show when={!isCompound()}>{renderPrimitive()}</Show>
        </>
    );
}

function collectPaths(value: unknown, prefix: string): string[] {
    const paths: string[] = [];
    if (value !== null && typeof value === "object") {
        paths.push(prefix);
        const entries = Array.isArray(value)
            ? value.map((item, index) => ({ key: String(index), value: item }))
            : Object.entries(value);
        for (const entry of entries) {
            paths.push(...collectPaths(entry.value, `${prefix}.${entry.key}`));
        }
    }
    return paths;
}

function escapeString(value: string): string {
    return value.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\n/g, "\\n").replace(/\t/g, "\\t");
}

import { createSignal, type JSX } from "solid-js";
import { Button } from "@/components/primitives/Button";
import { JsonTreeViewer } from "@/components/logs/JsonTreeViewer";

const SIMPLE_OBJECT = {
    name: "Alice",
    age: 30,
    active: true,
    email: null,
};

const NESTED_OBJECT = {
    user: {
        id: "usr_123",
        profile: {
            firstName: "Bob",
            lastName: "Smith",
            address: {
                street: "123 Main St",
                city: "Portland",
                state: "OR",
                zip: "97201",
            },
        },
        roles: ["admin", "editor"],
        settings: {
            theme: "dark",
            notifications: true,
            language: "en",
        },
    },
    metadata: {
        createdAt: "2025-01-15T10:30:00Z",
        version: 3,
    },
};

const LARGE_ARRAY = Array.from({ length: 20 }, (_, index) => ({
    id: index + 1,
    name: `Item ${index + 1}`,
    status: index % 3 === 0 ? "active" : index % 3 === 1 ? "pending" : "inactive",
    score: Math.round(Math.random() * 100),
    tags: [`tag-${index % 5}`, `category-${index % 3}`],
}));

const MIXED_TYPES = {
    string: "hello world",
    emptyString: "",
    integer: 42,
    float: 3.14159,
    negative: -17,
    boolTrue: true,
    boolFalse: false,
    nullValue: null,
    nestedArray: [1, "two", true, null, { nested: "object" }],
    deepNest: {
        level1: {
            level2: {
                level3: {
                    value: "deep",
                },
            },
        },
    },
};

export default function JsonTreeViewerDemo(): JSX.Element {
    const [expandGeneration, setExpandGeneration] = createSignal(0, { name: "expandGeneration" });
    const [collapseGeneration, setCollapseGeneration] = createSignal(0, { name: "collapseGeneration" });

    return (
        <div style={{ padding: "2rem", "max-width": "800px", margin: "0 auto" }} data-label="JsonTreeViewerDemo">
            <h1>JsonTreeViewer</h1>
            <p style={{ color: "var(--muted-foreground)", "margin-bottom": "2rem" }}>
                Interactive JSON tree with expand/collapse, hover highlight, and copy-to-clipboard for subtrees.
            </p>

            <div style={{ display: "flex", gap: "0.5rem", "margin-bottom": "2rem" }}>
                <Button variant="outline" size="small" onClick={() => setExpandGeneration((previous) => previous + 1)}>
                    Expand all
                </Button>
                <Button
                    variant="outline"
                    size="small"
                    onClick={() => setCollapseGeneration((previous) => previous + 1)}
                >
                    Collapse all
                </Button>
            </div>

            <div style={{ display: "flex", "flex-direction": "column", gap: "2rem" }}>
                <section>
                    <h3 style={{ "margin-bottom": "0.5rem" }}>Simple object</h3>
                    <JsonTreeViewer
                        data={SIMPLE_OBJECT}
                        defaultExpandDepth={2}
                        expandGeneration={expandGeneration()}
                        collapseGeneration={collapseGeneration()}
                    />
                </section>

                <section>
                    <h3 style={{ "margin-bottom": "0.5rem" }}>Nested object with arrays</h3>
                    <JsonTreeViewer
                        data={NESTED_OBJECT}
                        defaultExpandDepth={1}
                        expandGeneration={expandGeneration()}
                        collapseGeneration={collapseGeneration()}
                    />
                </section>

                <section>
                    <h3 style={{ "margin-bottom": "0.5rem" }}>Large array of objects</h3>
                    <JsonTreeViewer
                        data={LARGE_ARRAY}
                        defaultExpandDepth={0}
                        expandGeneration={expandGeneration()}
                        collapseGeneration={collapseGeneration()}
                    />
                </section>

                <section>
                    <h3 style={{ "margin-bottom": "0.5rem" }}>Mixed types</h3>
                    <JsonTreeViewer
                        data={MIXED_TYPES}
                        defaultExpandDepth={1}
                        expandGeneration={expandGeneration()}
                        collapseGeneration={collapseGeneration()}
                    />
                </section>
            </div>
        </div>
    );
}

