  1→import { createEffect, createSignal, For, type JSX, on, Show } from "solid-js";
  2→import { ChevronRight } from "@/components/icons";
  3→import { CopyButton } from "@/components/primitives/CopyButton";
  4→import styles from "./JsonTreeViewer.module.css";
  5→
  6→export function JsonTreeViewer(props: {
  7→    data: unknown;
  8→    defaultExpandDepth?: number;
  9→    expandGeneration?: number;
 10→    collapseGeneration?: number;
 11→}): JSX.Element {
 12→    const defaultDepth = () => props.defaultExpandDepth ?? 1;
 13→    const [expandState, setExpandState] = createSignal<Map<string, boolean>>(new Map(), {
 14→        name: "expandState",
 15→    });
 16→    const [hoveredPath, setHoveredPath] = createSignal<string | undefined>(undefined, {
 17→        name: "hoveredPath",
 18→    });
 19→
 20→    createEffect(
 21→        on(
 22→            () => props.expandGeneration,
 23→            (generation, previousGeneration) => {
 24→                if (generation === undefined || generation === previousGeneration) return;
 25→                const paths = collectPaths(props.data, "$");
 26→                const next = new Map<string, boolean>();
 27→                for (const path of paths) {
 28→                    next.set(path, true);
 29→                }
 30→                setExpandState(next);
 31→            },
 32→        ),
 33→    );
 34→
 35→    createEffect(
 36→        on(
 37→            () => props.collapseGeneration,
 38→            (generation, previousGeneration) => {
 39→                if (generation === undefined || generation === previousGeneration) return;
 40→                const paths = collectPaths(props.data, "$");
 41→                const next = new Map<string, boolean>();
 42→                for (const path of paths) {
 43→                    next.set(path, false);
 44→                }
 45→                setExpandState(next);
 46→            },
 47→        ),
 48→    );
 49→
 50→    const isExpanded = (path: string, depth: number): boolean => {
 51→        const explicit = expandState().get(path);
 52→        if (explicit !== undefined) return explicit;
 53→        return depth < defaultDepth();
 54→    };
 55→
 56→    const toggleExpanded = (path: string, depth: number) => {
 57→        const current = isExpanded(path, depth);
 58→        setExpandState((previous) => {
 59→            const next = new Map(previous);
 60→            next.set(path, !current);
 61→            return next;
 62→        });
 63→    };
 64→
 65→    return (
 66→        <div class={styles.container} data-label="JsonTreeViewer">
 67→            <JsonNode
 68→                value={props.data}
 69→                path="$"
 70→                depth={0}
 71→                isExpanded={isExpanded}
 72→                toggleExpanded={toggleExpanded}
 73→                hoveredPath={hoveredPath}
 74→                setHoveredPath={setHoveredPath}
 75→            />
 76→        </div>
 77→    );
 78→}
 79→
 80→function JsonNode(props: {
 81→    value: unknown;
 82→    path: string;
 83→    depth: number;
 84→    keyName?: string;
 85→    isLast?: boolean;
 86→    isExpanded: (path: string, depth: number) => boolean;
 87→    toggleExpanded: (path: string, depth: number) => void;
 88→    hoveredPath: () => string | undefined;
 89→    setHoveredPath: (path: string | undefined) => void;
 90→}): JSX.Element {
 91→    const isLast = () => props.isLast !== false;
 92→    const comma = () => (isLast() ? "" : ",");
 93→
 94→    const isCompound = () => {
 95→        const value = props.value;
 96→        return value !== null && typeof value === "object";
 97→    };
 98→
 99→    const isHighlighted = () => isCompound() && props.hoveredPath() === props.path;
100→
101→    const onMouseEnter = (event: MouseEvent) => {
102→        event.stopPropagation();
103→        props.setHoveredPath(props.path);
104→    };
105→
106→    const onMouseLeave = (event: MouseEvent) => {
107→        event.stopPropagation();
108→        if (props.hoveredPath() === props.path) {
109→            props.setHoveredPath(undefined);
110→        }
111→    };
112→
113→    const keyPrefix = (): JSX.Element => (
114→        <Show when={props.keyName !== undefined}>
115→            <span class={styles["property-name"]}>"{props.keyName}"</span>
116→            <span class={styles.punctuation}>: </span>
117→        </Show>
118→    );
119→
120→    // Primitive values
121→    const renderPrimitive = (): JSX.Element => {
122→        const value = props.value;
123→        if (value === null) {
124→            return (
125→                <div>
126→                    {keyPrefix()}
127→                    <span class={styles.null}>null</span>
128→                    {comma()}
129→                </div>
130→            );
131→        }
132→        if (typeof value === "string") {
133→            return (
134→                <div>
135→                    {keyPrefix()}
136→                    <span class={styles.string}>"{escapeString(value)}"</span>
137→                    {comma()}
138→                </div>
139→            );
140→        }
141→        if (typeof value === "number") {
142→            return (
143→                <div>
144→                    {keyPrefix()}
145→                    <span class={styles.number}>{String(value)}</span>
146→                    {comma()}
147→                </div>
148→            );
149→        }
150→        if (typeof value === "boolean") {
151→            return (
152→                <div>
153→                    {keyPrefix()}
154→                    <span class={styles.boolean}>{String(value)}</span>
155→                    {comma()}
156→                </div>
157→            );
158→        }
159→        return (
160→            <div>
161→                {keyPrefix()}
162→                <span>{String(value)}</span>
163→                {comma()}
164→            </div>
165→        );
166→    };
167→
168→    // Compound values (object/array)
169→    const renderCompound = (): JSX.Element => {
170→        const value = props.value as Record<string, unknown> | unknown[];
171→        const isArray = Array.isArray(value);
172→        const openBracket = isArray ? "[" : "{";
173→        const closeBracket = isArray ? "]" : "}";
174→        const entries = isArray
175→            ? value.map((item, index) => ({ key: String(index), value: item }))
176→            : Object.entries(value);
177→        const count = entries.length;
178→        const expanded = () => props.isExpanded(props.path, props.depth);
179→        const preview = () => (isArray ? `${count} items` : `${count} keys`);
180→
181→        return (
182→            // biome-ignore lint/a11y/noStaticElementInteractions: hover highlight for copy affordance, not interactive
183→            <div
184→                class={`${styles.node} ${isHighlighted() ? styles["node-highlighted"] : ""}`}
185→                onMouseEnter={onMouseEnter}
186→                onMouseLeave={onMouseLeave}
187→            >
188→                <Show when={isHighlighted()}>
189→                    <div class={styles["copy-wrapper"]}>
190→                        <CopyButton text={JSON.stringify(props.value, null, 2)} />
191→                    </div>
192→                </Show>
193→                <div>
194→                    <button
195→                        type="button"
196→                        class={styles.toggle}
197→                        onClick={() => props.toggleExpanded(props.path, props.depth)}
198→                    >
199→                        <ChevronRight
200→                            size={14}
201→                            class={`${styles.chevron} ${expanded() ? styles["chevron-expanded"] : ""}`}
202→                        />
203→                    </button>
204→                    {keyPrefix()}
205→                    <span class={styles.punctuation}>{openBracket}</span>
206→                    <Show when={!expanded()}>
207→                        <button
208→                            type="button"
209→                            class={`${styles.toggle} ${styles.preview}`}
210→                            onClick={() => props.toggleExpanded(props.path, props.depth)}
211→                        >
212→                            {" "}
213→                            ... {preview()}{" "}
214→                        </button>
215→                        <span class={styles.punctuation}>{closeBracket}</span>
216→                        {comma()}
217→                    </Show>
218→                </div>
219→                <Show when={expanded()}>
220→                    <div class={styles.children}>
221→                        <For each={entries}>
222→                            {(entry, index) => (
223→                                <JsonNode
224→                                    value={entry.value}
225→                                    path={`${props.path}.${entry.key}`}
226→                                    depth={props.depth + 1}
227→                                    keyName={isArray ? undefined : entry.key}
228→                                    isLast={index() === entries.length - 1}
229→                                    isExpanded={props.isExpanded}
230→                                    toggleExpanded={props.toggleExpanded}
231→                                    hoveredPath={props.hoveredPath}
232→                                    setHoveredPath={props.setHoveredPath}
233→                                />
234→                            )}
235→                        </For>
236→                    </div>
237→                    <div>
238→                        <span class={styles.punctuation}>{closeBracket}</span>
239→                        {comma()}
240→                    </div>
241→                </Show>
242→            </div>
243→        );
244→    };
245→
246→    return (
247→        <>
248→            <Show when={isCompound()}>{renderCompound()}</Show>
249→            <Show when={!isCompound()}>{renderPrimitive()}</Show>
250→        </>
251→    );
252→}
253→
254→function collectPaths(value: unknown, prefix: string): string[] {
255→    const paths: string[] = [];
256→    if (value !== null && typeof value === "object") {
257→        paths.push(prefix);
258→        const entries = Array.isArray(value)
259→            ? value.map((item, index) => ({ key: String(index), value: item }))
260→            : Object.entries(value);
261→        for (const entry of entries) {
262→            paths.push(...collectPaths(entry.value, `${prefix}.${entry.key}`));
263→        }
264→    }
265→    return paths;
266→}
267→
268→function escapeString(value: string): string {
269→    return value.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\n/g, "\\n").replace(/\t/g, "\\t");
270→}
